// ── toggle-button-group-alignment ─────────────────
type EvalToggleButtonGroupAlignmentAlignment = 'left' | 'center' | 'right';

function EvalToggleButtonGroupAlignment() {
  const [alignment, setAlignment] = useState<EvalToggleButtonGroupAlignmentAlignment>('left');

  return (
    <ToggleButtonGroup aria-label="Text alignment" size="md">
      <ToggleButton isSelected={alignment === 'left'} onChange={() => setAlignment('left')}>
        Left
      </ToggleButton>
      <ToggleButton isSelected={alignment === 'center'} onChange={() => setAlignment('center')}>
        Center
      </ToggleButton>
      <ToggleButton isSelected={alignment === 'right'} onChange={() => setAlignment('right')}>
        Right
      </ToggleButton>
    </ToggleButtonGroup>
  );
}

